// Normalize lead data from GHL webhook
// GHL sends different shapes depending on trigger type
const body = $input.item.json.body || {};

// Support multiple GHL event types
const eventType = body.type || body.event || 'contact.create';

// Extract core lead fields across GHL payload variations
const lead = {
  // Identity
  ghl_contact_id: body.contact_id || body.id || body.contactId || '',
  ghl_opportunity_id: body.opportunity_id || body.opportunityId || '',
  ghl_location_id: body.location_id || body.locationId || '',
  event_type: eventType,

  // Contact info
  first_name: body.first_name || body.firstName || body.contact?.firstName || '',
  last_name: body.last_name || body.lastName || body.contact?.lastName || '',
  email: body.email || body.contact?.email || '',
  phone: body.phone || body.phone_number || body.contact?.phone || '',
  company: body.company_name || body.companyName || body.contact?.companyName || '',

  // Lead intelligence
  source: body.source || body.lead_source || body.contact?.source || 'Unknown',
  tags: (body.tags || body.contact?.tags || []).join(', '),
  custom_fields: JSON.stringify(body.custom_fields || body.customFields || {}),
  pipeline_stage: body.pipeline_stage_name || body.pipelineStageName || '',
  pipeline_value: parseFloat(body.monetary_value || body.monetaryValue || 0),

  // Form / message data
  message: body.message || body.notes || body.contact?.notes || '',
  form_name: body.form_name || body.formName || '',
  form_data: JSON.stringify(body.form_fields || body.formData || {}),

  // Metadata
  received_at: new Date().toISOString(),
  full_name: `${body.first_name || body.firstName || ''} ${body.last_name || body.lastName || ''}`.trim() || 'Unknown Lead'
};

// Build enriched context string for AI qualification
lead.ai_context = [
  `Name: ${lead.full_name}`,
  `Email: ${lead.email}`,
  `Phone: ${lead.phone}`,
  `Company: ${lead.company || 'Not provided'}`,
  `Source: ${lead.source}`,
  `Tags: ${lead.tags || 'None'}`,
  `Pipeline Stage: ${lead.pipeline_stage || 'New'}`,
  `Deal Value: $${lead.pipeline_value}`,
  `Message: ${lead.message || 'None'}`,
  `Form: ${lead.form_name || 'N/A'}`,
  `Form Data: ${lead.form_data}`,
  `Custom Fields: ${lead.custom_fields}`
].join('\n');

return [{ json: lead }];

// Parse Claude's qualification response
const response = $input.item.json;
const lead = $('Normalize Lead Data').item.json;

let qualification;
try {
  const content = response.content?.[0]?.text || '{}';
  // Strip any accidental markdown
  const cleaned = content.replace(/```json|```/g, '').trim();
  qualification = JSON.parse(cleaned);
} catch (e) {
  // Fallback if AI response parsing fails
  qualification = {
    score: 30,
    tier: 'cold',
    budget_signal: false,
    authority_signal: false,
    need_signal: false,
    timeline_signal: false,
    assigned_team: 'nurture',
    priority: 'low',
    qualification_notes: 'AI qualification failed — manual review required.',
    follow_up_action: 'Review lead manually and qualify.',
    follow_up_delay_minutes: 60
  };
}

// Merge lead + qualification into single enriched object
return [{
  json: {
    ...lead,
    ...qualification,
    // Routing metadata
    routed_at: new Date().toISOString(),
    routing_status: 'pending',
    // GHL tag to apply
    ghl_tag: `ai-${qualification.tier}-${qualification.assigned_team}`,
    // Slack channel by team
    slack_channel: {
      enterprise: '#leads-enterprise',
      smb: '#leads-smb',
      nurture: '#leads-nurture'
    }[qualification.assigned_team] || '#leads-general'
  }
}];

