parameters.jsCode:
// Build Slack notification message
const lead = $input.item.json;

// Tier-based emoji and color
const tierConfig = {
  hot:  { emoji: '🔥', color: '#FF4444', urgency: 'CALL NOW — within 5 minutes' },
  warm: { emoji: '♨️',  color: '#FF8C00', urgency: 'Follow up within 30 minutes' },
  cold: { emoji: '🧊',  color: '#4A90D9', urgency: 'Enrolled in nurture sequence' }
};

const config = tierConfig[lead.tier] || tierConfig.cold;

// Build BANT signal string
const bant = [
  lead.budget_signal   ? '✅ Budget'   : '❌ Budget',
  lead.authority_signal ? '✅ Authority' : '❌ Authority',
  lead.need_signal      ? '✅ Need'     : '❌ Need',
  lead.timeline_signal  ? '✅ Timeline' : '❌ Timeline'
].join('  ');

// Score bar (visual)
const filled = Math.round((lead.score / 100) * 10);
const scoreBar = '█'.repeat(filled) + '░'.repeat(10 - filled);

return [{
  json: {
    ...lead,
    slack_message: {
      channel: lead.slack_channel,
      text: `${config.emoji} New ${lead.tier.toUpperCase()} Lead: ${lead.full_name}`,
      attachments: [
        {
          color: config.color,
          blocks: [
            {
              type: 'header',
              text: {
                type: 'plain_text',
                text: `${config.emoji} ${lead.tier.toUpperCase()} LEAD — ${config.urgency}`
              }
            },
            {
              type: 'section',
              fields: [
                { type: 'mrkdwn', text: `*Name:*\n${lead.full_name}` },
                { type: 'mrkdwn', text: `*Company:*\n${lead.company || 'N/A'}` },
                { type: 'mrkdwn', text: `*Email:*\n${lead.email}` },
                { type: 'mrkdwn', text: `*Phone:*\n${lead.phone || 'N/A'}` },
                { type: 'mrkdwn', text: `*Source:*\n${lead.source}` },
                { type: 'mrkdwn', text: `*Deal Value:*\n$${lead.pipeline_value || 0}` }
              ]
            },
            {
              type: 'section',
              text: {
                type: 'mrkdwn',
                text: `*AI Score:* ${lead.score}/100  \`${scoreBar}\`\n*BANT:* ${bant}`
              }
            },
            {
              type: 'section',
              text: {
                type: 'mrkdwn',
                text: `*AI Analysis:*\n${lead.qualification_notes}`
              }
            },
            {
              type: 'section',
              text: {
                type: 'mrkdwn',
                text: `*📋 Recommended Action:*\n${lead.follow_up_action}`
              }
            },
            {
              type: 'section',
              text: {
                type: 'mrkdwn',
                text: `*Team:* ${lead.assigned_team.toUpperCase()}  |  *Priority:* ${lead.priority.toUpperCase()}  |  *GHL Tag:* \`${lead.ghl_tag}\``
              }
            }
          ]
        }
      ]
    }
  }
}];

// Log the full routing result for analytics
const lead = $('Parse AI Qualification').item.json;
const slackResult = $input.item.json;

console.log(JSON.stringify({
  event: 'lead_routed',
  contact_id: lead.ghl_contact_id,
  full_name: lead.full_name,
  email: lead.email,
  score: lead.score,
  tier: lead.tier,
  assigned_team: lead.assigned_team,
  priority: lead.priority,
  source: lead.source,
  pipeline_value: lead.pipeline_value,
  budget_signal: lead.budget_signal,
  authority_signal: lead.authority_signal,
  need_signal: lead.need_signal,
  timeline_signal: lead.timeline_signal,
  routed_at: lead.routed_at,
  slack_ok: slackResult.ok || false
}));

return [{ json: { status: 'routed', lead_id: lead.ghl_contact_id, tier: lead.tier, score: lead.score } }];

